class Solution {
    public List<List<Integer>> pacificAtlantic(int[][] heights) {
        List<List<Integer>> res = new ArrayList<>();
        int m = heights.length, n = heights[0].length;
        boolean[][] pac = new boolean[m][n], atl = new boolean[m][n];
        for (int i = 0; i < m; i++) { dfs(heights, i, 0, pac); dfs(heights, i, n-1, atl); }
        for (int j = 0; j < n; j++) { dfs(heights, 0, j, pac); dfs(heights, m-1, j, atl); }
        for (int i = 0; i < m; i++) 
            for (int j = 0; j < n; j++) 
                if (pac[i][j] && atl[i][j]) res.add(Arrays.asList(i, j));
        return res;
    }
    private void dfs(int[][] h, int r, int c, boolean[][] visit) {
        visit[r][c] = true;
        int[][] dirs = {{1,0},{-1,0},{0,1},{0,-1}};
        for (int[] d : dirs) {
            int nr = r + d[0], nc = c + d[1];
            if (nr >= 0 && nr < h.length && nc >= 0 && nc < h[0].length && !visit[nr][nc] && h[nr][nc] >= h[r][c])
                dfs(h, nr, nc, visit);
        }
    }
}

