        for (int c = 0; c < board.length; c++) {
            if (cols.contains(c) || posD.contains(r+c) || negD.contains(r-c)) continue;
            cols.add(c); posD.add(r+c); negD.add(r-c); board[r][c] = 'Q';
            dfs(r + 1, cols, posD, negD, board, res);
            cols.remove(c); posD.remove(r+c); negD.remove(r-c); board[r][c] = '.';
        }
    }
}

