class Solution {
    public String minWindow(String s, String t) {
        if (s.length() < t.length()) return "";
        Map<Character, Integer> counts = new HashMap<>();
        for (char c : t.toCharArray()) counts.put(c, counts.getOrDefault(c, 0) + 1);
        int l = 0, minL = Integer.MAX_VALUE, start = 0, matched = 0;
        for (int r = 0; r < s.length(); r++) {
            char right = s.charAt(r);
            if (counts.containsKey(right)) {
                counts.put(right, counts.get(right) - 1);
                if (counts.get(right) == 0) matched++;
            }
            while (matched == counts.size()) {
                if (r - l + 1 < minL) {
                    minL = r - l + 1;
                    start = l;
                }
                char left = s.charAt(l++);
                if (counts.containsKey(left)) {
                    if (counts.get(left) == 0) matched--;
                    counts.put(left, counts.get(left) + 1);
                }
            }
        }
        return minL == Integer.MAX_VALUE ? "" : s.substring(start, start + minL);
    }
}

