class Solution {
    public int largestRectangleArea(int[] h) {
        int n = h.length, maxA = 0;
        Stack<Integer> s = new Stack<>();
        for (int i = 0; i <= n; i++) {
            int currH = (i == n) ? 0 : h[i];
            while (!s.isEmpty() && currH < h[s.peek()]) {
                int height = h[s.pop()];
                int width = s.isEmpty() ? i : i - s.peek() - 1;
                maxA = Math.max(maxA, height * width);
            }
            s.push(i);
        }
        return maxA;
    }
}

class Solution:
    def evalRPN(self, tokens: List[str]) -> int:
        stack = []
        for c in tokens:
            if c == '+': stack.append(stack.pop() + stack.pop())
            elif c == '-': a, b = stack.pop(), stack.pop(); stack.append(b - a)
            elif c == '*': stack.append(stack.pop() * stack.pop())
            elif c == '/': a, b = stack.pop(), stack.pop(); stack.append(int(b / a))
            else: stack.append(int(c))
        return stack[0]

